import{_ as t,o as i,c as o,ae as a}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"Improved Deep Linking without Attribution","description":"","frontmatter":{"title":"Improved Deep Linking without Attribution","slug":"improved-deep-linking-without-attribution"},"headers":[],"relativePath":"account-hub/improved-deep-linking-without-attribution.md","filePath":"account-hub/improved-deep-linking-without-attribution.md"}'),n={name:"account-hub/improved-deep-linking-without-attribution.md"};function l(r,e,s,h,d,p){return i(),o("div",null,[...e[0]||(e[0]=[a('<p>We&#39;re expanding the use of a deep linking key with more functionality. Learn more in this update 🔗</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Before, users can add the <code>$deeplink_no_attribution</code> <a href="./deep-link-data-options.html">Deep Link Data Key</a> to their Branch Ad Links to utilize a deep link for user experience on self-attributing networks (SAN) without impacting last touch attribution. Now you can use this key to support deep linking without attribution in other channels outside of ads. With this key, you don&#39;t have to worry about links deployed for user experience claiming attribution outside of existing campaigns.</p><table tabindex="0"><thead><tr><th>Key</th><th>Description</th><th>When to use</th></tr></thead><tbody><tr><td><code>$deeplink_no_attribution</code></td><td>Set to true for the links to only support deep linking without any attribution for that link.</td><td>For paid ads (ex. SANs) and non-ad links (ex. Short Link, Email, Journeys)</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Metrics</p><p>Using <code>$deeplink_no_attribution</code> will lose all link metrics when set to true on your Branch Link.</p></div><h3 id="example-use-cases" tabindex="-1">Example Use Cases <a class="header-anchor" href="#example-use-cases" aria-label="Permalink to &quot;Example Use Cases&quot;">​</a></h3><h4 id="paid-ad-link-to-mobile-website" tabindex="-1">Paid Ad Link to Mobile Website <a class="header-anchor" href="#paid-ad-link-to-mobile-website" aria-label="Permalink to &quot;Paid Ad Link to Mobile Website&quot;">​</a></h4><ol><li><p>User clicks a paid ad link (ex. Facebook ad) that leads user to mobile website</p></li><li><p>User sees and clicks a CTA on mobile website to download the app (CTA is a Branch Short Link)</p><ol><li>The Short Link has <code>$deeplink_no_attribution</code> key set to true</li></ol></li><li><p>The app session will be attributed to the original paid ad link <em>not</em> the Short Link</p></li></ol><h4 id="user-authentication-in-email" tabindex="-1">User Authentication in Email <a class="header-anchor" href="#user-authentication-in-email" aria-label="Permalink to &quot;User Authentication in Email&quot;">​</a></h4><ol><li><p>User interacts with an email campaign with links to a product</p></li><li><p>User initiates an authentication flow that utilizes a Branch Link</p><ol><li>The Branch Link has <code>$deeplink_no_attribution</code> key set to true</li></ol></li><li><p>The app session will be attributed to the email campaign</p></li></ol><h4 id="sharing-to-mobile-web" tabindex="-1">Sharing to Mobile Web <a class="header-anchor" href="#sharing-to-mobile-web" aria-label="Permalink to &quot;Sharing to Mobile Web&quot;">​</a></h4><ol><li><p>A user is sent to your mobile website through a sharing/referral link (Branch Link).</p></li><li><p>The user then sees a Branch Short Link on the mobile website that leads them to download/install the app.</p><ol><li>The Short Link has <code>$deeplink_no_attribution</code> key set to true</li></ol></li><li><p>The install/open event of the app will be attributed to the original sharing/referral link <em>not</em> the Short Link.</p></li></ol><blockquote><p>Looking to learn more about Deep Link Data Options? View our guide here: <a href="./deep-link-data-options.html">Deep Link Data Options</a></p></blockquote>',13)])])}const b=t(n,[["render",l]]);export{c as __pageData,b as default};
